// ItemDataAsset.h — defines what an item IS
UCLASS()
class UItemDataAsset : public UPrimaryDataAsset
{
    GENERATED_BODY()
public:
    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    FName ItemID;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    FText DisplayName;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    FText Description;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    TSoftObjectPtr<UTexture2D> Icon;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    int32 MaxStackSize = 1;

    UPROPERTY(EditDefaultsOnly, BlueprintReadOnly)
    EItemType ItemType; // Weapon, Consumable, Material, Quest
};

// InventorySlot — what the inventory stores
USTRUCT(BlueprintType)
struct FInventorySlot
{
    GENERATED_BODY()

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    UItemDataAsset* Item = nullptr;

    UPROPERTY(EditAnywhere, BlueprintReadWrite)
    int32 Count = 0;
};

// InventoryComponent.h — manages the slots
UCLASS(ClassGroup=(Custom), meta=(BlueprintSpawnableComponent))
class UInventoryComponent : public UActorComponent
{
    GENERATED_BODY()
public:
    UPROPERTY(EditAnywhere, BlueprintReadOnly, Category = "Inventory")
    int32 MaxSlots = 20;

    DECLARE_DYNAMIC_MULTICAST_DELEGATE(FOnInventoryChanged);

    UPROPERTY(BlueprintAssignable)
    FOnInventoryChanged OnInventoryChanged;

    UFUNCTION(BlueprintCallable)
    bool AddItem(UItemDataAsset* Item, int32 Amount = 1);

    UFUNCTION(BlueprintCallable)
    bool RemoveItem(UItemDataAsset* Item, int32 Amount = 1);

    UFUNCTION(BlueprintCallable, BlueprintPure)
    int32 GetItemCount(UItemDataAsset* Item) const;

protected:
    UPROPERTY(Replicated)
    TArray<FInventorySlot> Slots;
};
